{
  "name": "n8n-nodes-cloudflare-plus",
  "version": "0.1.13",
  "description": "An n8n community node for managing Cloudflare resources (Zones, DNS records, Firewall rules, Cache, Workers, Analytics).",
  "keywords": [
    "n8n-community-node-package"
  ],
  "license": "MIT",
  "homepage": "",
  "author": {
    "name": "Quales",
    "email": "contact-n8n@quales.me",
    "url": "https://quales.me"
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/Quales-N8N/n8n-nodes-cloudflare-plus.git"
  },
  "engines": {
    "node": ">=20.15"
  },
  "main": "index.js",
  "scripts": {
    "build": "npx rimraf dist && tsc && gulp build:icons",
    "dev": "tsc --watch",
    "format": "prettier nodes credentials --write",
    "lint": "eslint nodes credentials package.json",
    "lintfix": "eslint nodes credentials package.json --fix",
    "test": "vitest run",
    "prepublishOnly": "npm run build && npm run lint -c .eslintrc.prepublish.js nodes credentials package.json"
  },
  "files": [
    "dist"
  ],
  "n8n": {
    "n8nNodesApiVersion": 1,
    "credentials": [
      "dist/credentials/CloudflareApi.credentials.js",
      "dist/credentials/SimpleLoginApi.credentials.js"
    ],
    "nodes": [
      "dist/nodes/Cloudflare/Cloudflare.node.js",
      "dist/nodes/SimpleLogin/SimpleLogin.node.js"
    ]
  },
  "devDependencies": {
    "@typescript-eslint/parser": "~8.32.0",
    "eslint": "^8.57.0",
    "eslint-plugin-n8n-nodes-base": "^1.16.3",
    "gulp": "^5.0.0",
    "prettier": "^3.5.3",
    "typescript": "^5.8.2",
    "vitest": "^2.0.5",
    "ts-node": "^10.9.2"
  },
  "peerDependencies": {
    "n8n-workflow": "*"
  },
  "vitest": {
    "testTimeout": 20000
  }
}

